import 'package:go_router/go_router.dart';\nimport 'package:mystic_hub/presentation/pages/auth/auth_page.dart';\nimport 'package:mystic_hub/presentation/pages/home/home_page.dart';\nimport 'package:mystic_hub/presentation/pages/tap_game/tap_game_page.dart';\nimport 'package:mystic_hub/presentation/pages/academy/academy_page.dart';\nimport 'package:mystic_hub/presentation/pages/meme_realm/meme_realm_page.dart';\nimport 'package:mystic_hub/presentation/pages/profile/profile_page.dart';\nimport 'package:mystic_hub/presentation/pages/admin/admin_panel_page.dart';\nimport 'package:mystic_hub/presentation/pages/leaderboard/leaderboard_page.dart';\n\nfinal router = GoRouter(\n  initialLocation: '/auth',\n  routes: [\n    GoRoute(\n      path: '/auth',\n      builder: (context, state) => const AuthPage(),\n    ),\n    GoRoute(\n      path: '/home',\n      builder: (context, state) => const HomePage(),\n      routes: [\n        GoRoute(\n          path: 'game',\n          builder: (context, state) => const TapGamePage(),\n        ),\n        GoRoute(\n          path: 'academy',\n          builder: (context, state) => const AcademyPage(),\n        ),\n        GoRoute(\n          path: 'memes',\n          builder: (context, state) => const MemeRealmPage(),\n        ),\n        GoRoute(\n          path: 'profile',\n          builder: (context, state) => const ProfilePage(),\n        ),\n        GoRoute(\n          path: 'leaderboard',\n          builder: (context, state) => const LeaderboardPage(),\n        ),\n        GoRoute(\n          path: 'admin',\n          builder: (context, state) => const AdminPanelPage(),\n        ),\n      ],\n    ),\n  ],\n);\n